/// <summary>
/// Abhinav - End Production order in parent entity
/// </summary>
/// <param name = "_prodParmHistoricalCost"></param>
protected void endProductionOrder(ProdParmHistoricalCost _prodParmHistoricalCost)
{
    try
    {
        ttsbegin;
        next endProductionOrder(_prodParmHistoricalCost);

        if(ETGCanadaParameters::find().EnableSubContractingPO)
        {
            ProdTable prodTable = ProdTable::find(_prodParmHistoricalCost.ProdId);

            if(prodTable && prodTable.ETGIsSubContractingOrder && prodTable.ETGParentProdId)
            {
                changecompany(prodTable.ETGParentEntity)
                {
                    ProdTable                   prodTableParent = ProdTable::find(prodTable.ETGParentProdId);

                    ProdMultiHistoricalCost prodMultiHistoricalCost = ProdMultiHistoricalCost::construct(new Args());
                    RunBaseMultiParm::initParm(prodMultiHistoricalCost);

                    prodMultiHistoricalCost.insert(prodTableParent, prodMultiHistoricalCost.defaultParmBuffer());
                    prodMultiHistoricalCost.run();
                }
            }
        }
        ttscommit;
    }
    catch
    {
        ttsabort;
    }
}
